mapper.select:
SELECT attempt_id
FROM QUIZ_ATTEMPT
WHERE user_id = #{userId}
  AND course_id = #{courseId}
  AND chapter_id = #{chapterId}

SELECT user_id
FROM QUIZ_ATTEMPT
WHERE attempt_id = #{attemptId}

SELECT qaa.attempt_answer_id AS wrongNoteId, qa.course_id AS courseId, qa.chapter_id AS chapterId, q.quiz_id AS quizId, c.course_title AS courseTitle, cc.chapter_title AS chapterTitle, DBMS_LOB.SUBSTR(q.question_text, 4000, 1) AS questionText, DBMS_LOB.SUBSTR(selected.option_text, 4000, 1) AS selectedOptionText, DBMS_LOB.SUBSTR(correct.option_text, 4000, 1) AS correctOptionText, DBMS_LOB.SUBSTR(q.explanation, 4000, 1) AS explanation, qa.submitted_at AS createdAt FROM QUIZ_ATTEMPT qa JOIN COURSE c ON c.course_id = qa.course_id JOIN COURSE_CHAPTER cc ON cc.chapter_id = qa.chapter_id JOIN QUIZ_ATTEMPT_ANSWER qaa ON qaa.attempt_id = qa.attempt_id JOIN QUIZ q ON q.quiz_id = qaa.quiz_id LEFT JOIN QUIZ_OPTION selected ON selected.option_id = qaa.selected_option_id LEFT JOIN QUIZ_OPTION correct ON correct.quiz_id = q.quiz_id AND correct.correct_yn = 'Y' WHERE qa.user_id = #{userId} AND qaa.correct_yn = 'N'
AND qa.course_id = #{courseId}
AND qa.chapter_id = #{chapterId}
ORDER BY qa.submitted_at DESC, qaa.attempt_answer_id DESC
